      : _entries = List<String>.unmodifiable(entries);

  final List<String> _entries;

  bool trusts(String address, {String? forwardedFor}) {
    final trimmedAddress = address.trim();
    for (final entry in _entries) {
      if (entry.endsWith('/')) {
        // CIDR range
        final cidrParts = entry.split('/');
        final ipParts = forwardedFor != null ? forwardedFor.split('.') : trimmedAddress.split('.');
        final networkPart = cidrParts[0].split('.');
        final prefixLength = int.parse(cidrParts[1]);
        for (int i = 0; i < prefixLength; i++) {
          if (int.parse(ipParts[i]) != int.parse(networkPart[i])) {
            break;
          }
        }
        if (i == prefixLength) {
          return true;
        }
      } else {
        // Single IP address
        if (forwardedFor != null ? forwardedFor == entry : trimmedAddress == entry) {
          return true;
        }
      }
    }
    return false;
  }
}
